import{_ as e,o as s,c as i,a2 as n}from"./chunks/framework.DCVnL8g5.js";const k=JSON.parse('{"title":"Capas y overlay filesystem","description":"","frontmatter":{},"headers":[],"relativePath":"herramientas/docker/08-capas-y-overlay-filesystem.md","filePath":"herramientas/docker/08-capas-y-overlay-filesystem.md","lastUpdated":1782521464000}'),l={name:"herramientas/docker/08-capas-y-overlay-filesystem.md"};function t(r,a,p,o,c,d){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="capas-y-overlay-filesystem" tabindex="-1">Capas y overlay filesystem <a class="header-anchor" href="#capas-y-overlay-filesystem" aria-label="Permalink to &quot;Capas y overlay filesystem&quot;">​</a></h1><p>Las imagenes Docker se construyen por capas. Cada instruccion del Dockerfile puede crear una capa reutilizable. En ejecucion, el contenedor anade una capa escribible encima de las capas de imagen.</p><h2 id="diagrama" tabindex="-1">Diagrama <a class="header-anchor" href="#diagrama" aria-label="Permalink to &quot;Diagrama&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[&quot;Container writable layer&quot;] --&gt; B[&quot;Image layer: app code&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[&quot;Image layer: dependencies&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; D[&quot;Image layer: runtime&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D --&gt; E[&quot;Image layer: base OS&quot;]</span></span></code></pre></div><h2 id="capas-de-imagen" tabindex="-1">Capas de imagen <a class="header-anchor" href="#capas-de-imagen" aria-label="Permalink to &quot;Capas de imagen&quot;">​</a></h2><p>Ejemplo:</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node:22-alpine</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WORKDIR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /app</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> package*.json ./</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> npm ci</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> . .</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">CMD</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;node&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;server.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>Cada paso relevante genera una capa o metadata. Si cambias <code>COPY . .</code>, Docker puede reutilizar capas anteriores.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Docker reutiliza cache si la instruccion y sus entradas no han cambiado.</p><p>Por eso conviene copiar primero archivos de dependencias:</p><div class="language-dockerfile vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> package*.json ./</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> npm ci</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> . .</span></span></code></pre></div><p>Si copias todo antes de instalar, cada cambio de codigo invalida la instalacion de dependencias.</p><h2 id="capa-escribible" tabindex="-1">Capa escribible <a class="header-anchor" href="#capa-escribible" aria-label="Permalink to &quot;Capa escribible&quot;">​</a></h2><p>Cuando un contenedor modifica archivos, escribe en su capa propia. Si eliminas el contenedor, esa capa desaparece.</p><p>Para persistir datos usa:</p><ul><li>Volumenes.</li><li>Bind mounts.</li><li>Almacenamiento externo.</li></ul><h2 id="overlay-filesystem" tabindex="-1">Overlay filesystem <a class="header-anchor" href="#overlay-filesystem" aria-label="Permalink to &quot;Overlay filesystem&quot;">​</a></h2><p>Docker suele usar un driver como <code>overlay2</code>. Su trabajo es presentar varias capas como si fueran un unico filesystem.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>lowerdir = capas de imagen</span></span>
<span class="line"><span>upperdir = capa escribible del contenedor</span></span>
<span class="line"><span>merged = vista final dentro del contenedor</span></span></code></pre></div><h2 id="implicaciones" tabindex="-1">Implicaciones <a class="header-anchor" href="#implicaciones" aria-label="Permalink to &quot;Implicaciones&quot;">​</a></h2><ul><li>Las imagenes comparten capas.</li><li>Los builds pueden ser rapidos si cachean bien.</li><li>Escribir muchos datos dentro del contenedor no es buena estrategia.</li><li>Borrar archivos de una capa anterior no reduce necesariamente el tamano final si ya quedaron en una capa previa.</li></ul><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Ordena instrucciones de menos cambiante a mas cambiante.</li><li>Usa multi-stage para no arrastrar dependencias de build.</li><li>No escribas datos persistentes en la capa del contenedor.</li><li>Limpia caches en la misma capa donde se generan.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Copiar secretos y borrarlos despues: pueden quedar en una capa anterior.</li><li>Invalidar cache con <code>COPY . .</code> demasiado pronto.</li><li>Usar contenedores como almacenamiento.</li><li>No entender por que una imagen pesa demasiado.</li></ul>`,26)])])}const u=e(l,[["render",t]]);export{k as __pageData,u as default};
